from flask import Flask, render_template, request, redirect, url_for
from flask_sqlalchemy import SQLAlchemy
from flask_login import LoginManager, UserMixin, login_user, login_required, logout_user
from werkzeug.security import generate_password_hash, check_password_hash
from pyotp import TOTP

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///database.db'
db = SQLAlchemy(app)

login_manager = LoginManager()
login_manager.init_app(app)

class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)
    secret_key = db.Column(db.String(16), nullable=True)

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        user = User.query.filter_by(username=username).first()

        if user and check_password_hash(user.password, password):
            return redirect(url_for('verify_mfa', user_id=user.id))

    return render_template('login.html')

@app.route('/verify-mfa/<user_id>', methods=['GET', 'POST'])
def verify_mfa(user_id):
    user = User.query.get(int(user_id))

    if request.method == 'POST':
        totp = TOTP(user.secret_key)
        otp_code = request.form['otp_code']

        if totp.verify(otp_code):
            login_user(user)
            return redirect(url_for('protected_resource'))

    return render_template('verify_mfa.html')

@app.route('/protected-resource')
@login_required
def protected_resource():
    return 'This is a protected resource.'

if __name__ == '__main__':
    app.run(debug=True)